# Extracted code implementing hypergraph-based (HSMM) inference and low-rank/mixed parameterization
# from the repository. These are the core components of the method:
#  - SemiMarkovModule: constructs dynamic-programming scores for an HSMM (DAG hypergraph) and runs exact DP
#    via torch_struct's SemiMarkovCRF (hypergraph-based inference / dynamic programming over labeled DAGs).
#  - ComponentSemiMarkovModule: parameter-ties transitions/initials/lengths/emissions through low-dimensional
#    embeddings and MLPs, yielding a low-rank parameterization (rank = embedding_dim) applied to bottleneck
#    (transition/length/emission mean) factors, while keeping exact DP.
#  - SemiMarkovModel: training loop (Adam) that maximizes (joint or conditional) log-likelihood with exact DP.
#  - CrosstaskDatasplit.get_allowed_starts_and_transitions: constructs banded/sparse transition constraints
#    (e.g., canonical order) that can be combined with the low-rank parameterization.
#  - NICETrans/Encoder: optional flow projection and residual MLPs used in the parameterization.

# ---- models/flow.py (projection via invertible coupling flow; used as feature projector) ----
from __future__ import print_function
import math
import torch
import torch.nn as nn
import torch.nn.functional as F

class ReLUNet(nn.Module):
    @classmethod
    def add_args(cls, parser):
        parser.add_argument('--flow_hidden_layers', type=int, default=1)
        parser.add_argument('--flow_hidden_units', type=int, default=100)

    def __init__(self, args, in_features, out_features):
        super(ReLUNet, self).__init__()
        self.args = args
        self.in_layer = nn.Linear(in_features, self.args.flow_hidden_units, bias=True)
        self.out_layer = nn.Linear(self.args.flow_hidden_units, out_features, bias=True)
        for i in range(self.args.flow_hidden_layers):
            name = 'cell{}'.format(i)
            cell = nn.Linear(self.args.flow_hidden_units, self.args.flow_hidden_units, bias=True)
            setattr(self, name, cell)

    def reset_parameters(self):
        self.in_layer.reset_parameters()
        self.out_layer.reset_parameters()
        for i in range(self.args.flow_hidden_layers):
            name = 'cell{}'.format(i)
            getattr(self, name).reset_parameters()

    def init_identity(self):
        self.in_layer.weight.data.zero_(); self.in_layer.bias.data.zero_()
        self.out_layer.weight.data.zero_(); self.out_layer.bias.data.zero_()
        for i in range(self.args.flow_hidden_layers):
            name = 'cell{}'.format(i)
            getattr(self, name).weight.data.zero_()
            getattr(self, name).bias.data.zero_()

    def forward(self, input):
        h = self.in_layer(input); h = F.relu(h)
        for i in range(self.args.flow_hidden_layers):
            name = 'cell{}'.format(i)
            h = getattr(self, name)(h); h = F.relu(h)
        return self.out_layer(h)

class NICETrans(nn.Module):
    @classmethod
    def add_args(cls, parser):
        ReLUNet.add_args(parser)
        parser.add_argument('--flow_couple_layers', type=int, default=4)
        parser.add_argument('--flow_scale', action='store_true')
        parser.add_argument('--flow_scale_no_zero', action='store_true')

    def __init__(self, args, features):
        super(NICETrans, self).__init__()
        self.args = args
        for i in range(self.args.flow_couple_layers):
            name = 'cell{}'.format(i)
            cell = ReLUNet(args, features//2, features//2)
            setattr(self, name, cell)
            if args.flow_scale:
                name = 'scale_cell{}'.format(i)
                cell = ReLUNet(args, features//2, features//2)
                if not args.flow_scale_no_zero:
                    cell.init_identity()
                setattr(self, name, cell)

    def reset_parameters(self):
        for i in range(self.args.flow_couple_layers):
            name = 'cell{}'.format(i)
            getattr(self, name).reset_parameters()
            if self.args.flow_scale:
                name = 'scale_cell{}'.format(i)
                getattr(self, name).reset_parameters()

    def forward(self, input):
        jacobian_loss = torch.zeros(input.size(0), device=input.device, requires_grad=False)
        ep_size = input.size(); features = ep_size[-1]
        h = input
        for i in range(self.args.flow_couple_layers):
            name = 'cell{}'.format(i)
            h1, h2 = torch.split(h, features//2, dim=-1)
            if i%2 == 1: h1, h2 = h2, h1
            t = getattr(self, name)(h1)
            if self.args.flow_scale:
                s = getattr(self, 'scale_cell{}'.format(i))(h1)
                jacobian_loss += s.sum(dim=-1).sum(dim=-1)
                h2_p = torch.exp(s) * h2 + t
            else:
                h2_p = h2 + t
            if i%2 == 1: h1, h2_p = h2_p, h1
            h = torch.cat((h1, h2_p), dim=-1)
        return h, jacobian_loss

# ---- models/sequential.py (Encoder used for latent z in component HSMM) ----
import torch.nn as nn
class Encoder(nn.Module):
    @classmethod
    def add_args(cls, parser):
        parser.add_argument('--seq_num_layers', type=int, default=2)
    def __init__(self, args, input_dim, output_dim):
        super(Encoder, self).__init__()
        self.args = args
        assert output_dim % 2 == 0
        self.encoder = nn.LSTM(input_dim, output_dim // 2, bidirectional=True,
                               num_layers=args.seq_num_layers, batch_first=True)
    def flatten_parameters(self):
        self.encoder.flatten_parameters()
    def forward(self, features, lengths, output_padding_value=0):
        packed = nn.utils.rnn.pack_padded_sequence(features, lengths, batch_first=True, enforce_sorted=False)
        encoded_packed, _ = self.encoder(packed)
        encoded, _ = nn.utils.rnn.pad_packed_sequence(encoded_packed, batch_first=True, padding_value=output_padding_value)
        return encoded

# ---- models/semimarkov/semimarkov_modules.py (HSMM DP + parameterizations) ----
from typing import Dict, Set
import numpy as np
import torch
import torch.nn.functional as F
from torch import nn
from torch.autograd import Variable
from torch.distributions import MultivariateNormal, Poisson
from torch.nn.init import xavier_uniform_
from torch_struct import SemiMarkovCRF

BIG_NEG = -1e9
DEBUG_ANNOTATE = False

def sliding_sum(inputs, k):
    batch_size = inputs.size(0)
    assert k > 0
    if k == 1:
        return inputs
    sliding_windows = F.unfold(inputs.unsqueeze(1), kernel_size=(k, 1), padding=(k, 0))\
                        .reshape(batch_size, k, -1, inputs.size(-1))
    sliding_summed = sliding_windows.sum(dim=1)
    ret = sliding_summed[:, k:-1, :]
    assert ret.shape == inputs.shape
    return ret

class ResidualLayer(nn.Module):
    def __init__(self, in_dim=100, out_dim=100):
        super(ResidualLayer, self).__init__()
        self.lin1 = nn.Linear(in_dim, out_dim)
        self.lin2 = nn.Linear(out_dim, out_dim)
    def forward(self, x):
        return F.relu(self.lin2(F.relu(self.lin1(x)))) + x

class SemiMarkovModule(nn.Module):
    @classmethod
    def add_args(cls, parser):
        parser.add_argument('--sm_max_span_length', type=int, default=20)
        parser.add_argument('--sm_supervised_state_smoothing', type=float, default=1e-2)
        parser.add_argument('--sm_supervised_length_smoothing', type=float, default=1e-1)
        parser.add_argument('--sm_supervised_method', choices=['closed-form','gradient-based','closed-then-gradient'], default='closed-form')
        parser.add_argument('--sm_feature_projection', action='store_true')
        parser.add_argument('--sm_init_non_projection_parameters_from')
        NICETrans.add_args(parser)
    def __init__(self, args, n_classes, n_dims, allow_self_transitions=False,
                 allowed_starts: Set[int] = None, allowed_transitions: Dict[int, Set[int]] = None,
                 allowed_ends: Set[int] = None, merge_classes: Dict[int, int] = None):
        super(SemiMarkovModule, self).__init__()
        self.args = args
        self.n_classes = n_classes
        self.input_feature_dim = n_dims
        self.feature_dim = n_dims
        self.allow_self_transitions = allow_self_transitions
        self.init_params()
        if allowed_starts is not None:
            self.set_transition_constraints(allowed_starts, allowed_transitions, allowed_ends)
        else:
            self.remove_transition_constraints()
        if args.sm_init_non_projection_parameters_from is not None:
            import pickle
            print("loading all non-flow parameters from {}".format(args.sm_init_non_projection_parameters_from))
            with open(args.sm_init_non_projection_parameters_from, 'rb') as f:
                sm = pickle.load(f)
                self.init_nonproject_parameters(sm.model)
        self.init_projector()
        self.max_k = args.sm_max_span_length
        self._merge_classes = merge_classes
    @property
    def merge_classes(self):
        if hasattr(self, '_merge_classes'): return self._merge_classes
        else: return None
    def init_nonproject_parameters(self, model):
        assert isinstance(model, SemiMarkovModule)
        incompatible_keys = self.load_state_dict(model.state_dict(), strict=False)
        assert not incompatible_keys.unexpected_keys
        assert all(k.startswith("feature_projector") for k in incompatible_keys.missing_keys)
    def init_projector(self):
        if self.args.sm_feature_projection:
            self.feature_projector = NICETrans(self.args, features=self.feature_dim)
        else:
            self.feature_projector = None
    def init_params(self):
        poisson_log_rates = torch.zeros(self.n_classes).float()
        self.poisson_log_rates = nn.Parameter(poisson_log_rates, requires_grad=True)
        gaussian_means = torch.zeros(self.n_classes, self.feature_dim).float()
        self.gaussian_means = nn.Parameter(gaussian_means, requires_grad=True)
        gaussian_cov = torch.eye(self.feature_dim).float()
        self.gaussian_cov = nn.Parameter(gaussian_cov, requires_grad=False)
        transition_logits = torch.zeros(self.n_classes, self.n_classes).float()
        self.transition_logits = nn.Parameter(transition_logits, requires_grad=True)
        init_logits = torch.zeros(self.n_classes).float()
        self.init_logits = nn.Parameter(init_logits, requires_grad=True)
        torch.nn.init.uniform_(self.init_logits, 0, 1)
    def flatten_parameters(self):
        pass
    def remove_transition_constraints(self):
        self.transition_constraints = None
        self.init_constraints = None
        self.allowed_ends = None
    def set_transition_constraints(self, allowed_starts: Set[int], allowed_transitions: Dict[int, Set[int]], allowed_ends: Set[int]):
        self.init_constraints = nn.Parameter(torch.full((self.n_classes,), 1, dtype=torch.bool), requires_grad=False)
        assert all(x >= 0 for x in allowed_starts)
        self.init_constraints[torch.LongTensor(list(sorted(allowed_starts)))] = 0
        self.transition_constraints = nn.Parameter(torch.full((self.n_classes, self.n_classes), 1, dtype=torch.bool), requires_grad=False)
        for src, targets in allowed_transitions.items():
            for tgt in targets:
                self.transition_constraints[tgt,src] = 0
        self.allowed_ends = allowed_ends
    def fit_supervised(self, feature_list, label_list):
        from .semimarkov_utils import semimarkov_sufficient_stats
        if self.feature_projector is not None:
            raise NotImplementedError("fit_supervised closed form with feature projector")
        if self.transition_constraints is not None or self.init_constraints is not None:
            raise NotImplementedError("fit_supervised closed form with constrained state transitions")
        emission_gmm, stats = semimarkov_sufficient_stats(feature_list, label_list, covariance_type='tied_diag', n_classes=self.n_classes, max_k=self.max_k)
        if self.merge_classes is not None:
            label_list_merged = [torch.LongTensor([self.merge_classes[ix.item()] for ix in labels]).to(labels.device) for labels in label_list]
            emission_gmm_merged, stats_merged = semimarkov_sufficient_stats(feature_list, label_list_merged, covariance_type='tied_diag', n_classes=self.n_classes, max_k=self.max_k)
        else:
            emission_gmm_merged, stats_merged = emission_gmm, stats
        if DEBUG_ANNOTATE:
            emission_gmm = emission_gmm_merged; stats = stats_merged
        init_probs = (stats['span_start_counts'] + self.args.sm_supervised_state_smoothing) / float(stats['instance_count'] + self.args.sm_supervised_state_smoothing * self.n_classes)
        init_probs[np.isnan(init_probs)] = 0
        self.init_logits.data.zero_(); self.init_logits.data.add_(torch.from_numpy(init_probs).to(device=self.init_logits.device).log())
        smoothed_trans_counts = stats['span_transition_counts'] + self.args.sm_supervised_state_smoothing
        trans_probs = smoothed_trans_counts / smoothed_trans_counts.sum(axis=0)[None, :]
        trans_probs[np.isnan(trans_probs)] = 0
        self.transition_logits.data.zero_(); self.transition_logits.data.add_(torch.from_numpy(trans_probs).to(device=self.transition_logits.device).log())
        mean_lengths = (stats_merged['span_lengths'] + self.args.sm_supervised_length_smoothing) / (stats_merged['span_counts'] + self.args.sm_supervised_length_smoothing)
        self.poisson_log_rates.data.zero_(); self.poisson_log_rates.data.add_(torch.from_numpy(mean_lengths).to(device=self.poisson_log_rates.device).log())
        self.gaussian_means.data.zero_(); self.gaussian_means.data.add_(torch.from_numpy(emission_gmm_merged.means_).to(device=self.gaussian_means.device).float())
        self.gaussian_cov.data.zero_(); self.gaussian_cov.data.add_(torch.diag(torch.from_numpy(emission_gmm_merged.covariances_[0]).to(device=self.gaussian_cov.device).float()))
    def _initialize_gaussian_means(self, mean):
        self.gaussian_means.data.zero_(); self.gaussian_means.data.add_(mean.expand((self.n_classes, self.feature_dim)))
    def initialize_gaussian_from_feature_list(self, features):
        feats = torch.cat(features, dim=0)
        if self.feature_projector:
            feats, jacobian = self.feature_projector(feats)
        assert feats.dim() == 2
        n_dim = feats.size(1)
        assert n_dim == self.feature_dim
        mean = feats.mean(dim=0, keepdim=True)
        self._initialize_gaussian_means(mean)
        self.gaussian_cov.data = torch.diag(feats.var(dim=0))
    def initialize_gaussian(self, data, lengths):
        batch_size, N, n_dim = data.size(); assert lengths.size(0) == batch_size
        feats = []
        for i in range(batch_size): feats.append(data[i, :lengths[i]])
        self.initialize_gaussian_from_feature_list(feats)
    def initial_log_probs(self, valid_classes):
        logits = self.init_logits
        if self.init_constraints is not None:
            logits = logits.masked_fill(self.init_constraints, BIG_NEG)
        if DEBUG_ANNOTATE and self.merge_classes is not None and valid_classes is not None:
            valid_classes = torch.LongTensor([self.merge_classes[ix.item()] for ix in valid_classes]).to(logits.device)
        if valid_classes is not None:
            logits = logits[valid_classes]
        return F.log_softmax(logits, dim=0)
    def transition_log_probs(self, valid_classes):
        transition_logits = self.transition_logits
        if self.transition_constraints is not None:
            transition_logits = transition_logits.masked_fill(self.transition_constraints, BIG_NEG)
        if DEBUG_ANNOTATE and self.merge_classes is not None and valid_classes is not None:
            valid_classes = torch.LongTensor([self.merge_classes[ix.item()] for ix in valid_classes]).to(transition_logits.device)
        if valid_classes is not None:
            transition_logits = transition_logits[valid_classes][:, valid_classes]
            n_classes = len(valid_classes)
        else:
            n_classes = self.n_classes
        if self.allow_self_transitions:
            masked = transition_logits
        else:
            masked = transition_logits.masked_fill(torch.eye(n_classes, device=self.transition_logits.device).bool(), BIG_NEG)
        return F.log_softmax(masked, dim=0)  # column-normalized (to_state, from_state)
    def _emission_log_probs_with_means(self, features, class_means):
        B, N, d = features.size()
        if class_means.dim() == 2:
            num_classes, d_ = class_means.size(); assert d == d_, (d, d_)
            class_means = class_means.unsqueeze(0)
        else:
            _, num_classes, d_ = class_means.size(); assert d == d_, (d, d_)
        class_means = class_means.expand(B, num_classes, d)
        scale_tril = self.gaussian_cov.sqrt()
        log_probs = []
        for c in range(num_classes):
            this_means = class_means[:, c, :]
            dist = MultivariateNormal(loc=this_means, scale_tril=scale_tril)
            log_probs.append(dist.log_prob(features.transpose(0, 1)).transpose(0, 1).unsqueeze(-1))
        return torch.cat(log_probs, dim=2)
    def emission_log_probs(self, features, valid_classes, constraints):
        if valid_classes is None:
            class_indices = torch.LongTensor(list(range(self.n_classes))).to(self.gaussian_means.device)
        else:
            class_indices = valid_classes
        if self.merge_classes is not None:
            class_indices = torch.LongTensor([self.merge_classes[ix.item()] for ix in class_indices]).to(self.gaussian_means.device)
        class_means = self.gaussian_means[class_indices]
        elp = self._emission_log_probs_with_means(features, class_means)
        if constraints is not None:
            elp = elp + constraints
        return elp
    def _length_log_probs_with_rates(self, log_rates):
        n_classes = log_rates.size(-1); max_length = self.max_k
        time_steps = torch.arange(max_length, device=log_rates.device).unsqueeze(-1).expand(max_length, n_classes).float()
        if max_length == 1:
            return torch.FloatTensor([0, -1000]).unsqueeze(-1).expand(2, n_classes).to(log_rates.device)
        poissons = Poisson(torch.exp(log_rates))
        if log_rates.dim() == 2:
            time_steps = time_steps.unsqueeze(1).expand(max_length, log_rates.size(0), n_classes)
            return poissons.log_prob(time_steps).transpose(0, 1)
        else:
            assert log_rates.dim() == 1
            return poissons.log_prob(time_steps)
    def length_log_probs(self, valid_classes):
        if valid_classes is None:
            class_indices = torch.LongTensor(list(range(self.n_classes))).to(self.poisson_log_rates.device)
            n_classes = self.n_classes
        else:
            class_indices = valid_classes; n_classes = len(valid_classes)
        if self.merge_classes is not None:
            class_indices = torch.LongTensor([self.merge_classes[ix.item()] for ix in class_indices]).to(self.poisson_log_rates.device)
        log_rates = self.poisson_log_rates[class_indices]
        return self._length_log_probs_with_rates(log_rates)
    @staticmethod
    def log_hsmm(transition, emission_scores, init, length_scores, lengths, add_eos,
                 all_batched=False, allowed_ends_per_instance=None):
        b, N_1, C_1 = emission_scores.shape
        if all_batched:
            _, K, _C = length_scores.shape; assert C_1 == _C
        else:
            K, _C = length_scores.shape; assert C_1 == _C
            transition = transition.unsqueeze(0).expand(b, C_1, C_1)
            length_scores = length_scores.unsqueeze(0).expand(b, K, C_1)
            init = init.unsqueeze(0).expand(b, C_1)
        if K > N_1:
            K = N_1; length_scores = length_scores[:, :K]
        if add_eos:
            N = N_1 + 1; C = C_1 + 1
        else:
            N = N_1; C = C_1
        if add_eos:
            transition_augmented = torch.full((b, C, C), BIG_NEG, device=transition.device)
            transition_augmented[:, :C_1, :C_1] = transition
            if allowed_ends_per_instance is None:
                transition_augmented[:, C_1, :] = 0
            else:
                for i, allowed_ends in enumerate(allowed_ends_per_instance):
                    assert len(allowed_ends) > 0
                    transition_augmented[i, C_1, allowed_ends] = 0
            init_augmented = torch.full((b, C), BIG_NEG, device=init.device)
            init_augmented[:, :C_1] = init
            length_scores_augmented = torch.full((b, K, C), BIG_NEG, device=length_scores.device)
            length_scores_augmented[:, :, :C_1] = length_scores
            if length_scores_augmented.size(1) > 1:
                length_scores_augmented[:, 1, C_1] = 0
            else:
                length_scores_augmented[:, 0, C_1] = 0
            emission_augmented = torch.full((b, N, C), BIG_NEG, device=emission_scores.device)
            for i, length in enumerate(lengths):
                emission_augmented[i, :length, :C_1] = emission_scores[i, :length]
                emission_augmented[i, length, C_1] = 0
            lengths_augmented = lengths + 1
        else:
            transition_augmented = transition; init_augmented = init
            length_scores_augmented = length_scores; emission_augmented = emission_scores
            lengths_augmented = lengths
        scores = torch.zeros(b, N - 1, K, C, C, device=emission_scores.device).type_as(emission_scores)
        scores[:, :, :, :, :] += transition_augmented.view(b, 1, 1, C, C)
        scores[:, 0, :, :, :] += init_augmented.view(b, 1, 1, C)
        scores[:, :, :, :, :] += length_scores_augmented.view(b, 1, K, 1, C)
        for k in range(1, K):
            summed = sliding_sum(emission_augmented, k).view(b, N, 1, C)
            for i in range(b):
                length = lengths_augmented[i]
                scores[i, :length - 1, k, :, :] += summed[i, :length - 1]
                scores[i, length - 1 - k, k, :, :] += emission_augmented[i, length - 1].view(C, 1)
        return scores
    def add_eos(self, spans, lengths):
        b, N = spans.size()
        augmented = torch.cat([spans, torch.full([b, 1], -1, device=spans.device, dtype=torch.long)], dim=1)
        augmented[torch.arange(b), lengths] = self.n_classes
        return augmented
    def trim(self, spans, lengths, check_eos=False):
        b, N = spans.size(); indices = torch.arange(b)
        seqs = []
        for i in range(b): seqs.append(spans[i, :lengths[i]])
        return seqs
    @property
    def batched_scores(self):
        return False
    def set_z(self, features, lengths, use_mean=False):
        self.kl = Variable(torch.zeros(features.size(0)).to(features.device), requires_grad=True)
    def score_features(self, features, lengths, valid_classes, add_eos, use_mean_z,
                       additional_allowed_ends_per_instance=None, constraints=None, return_elp=False):
        self.set_z(features, lengths, use_mean=use_mean_z)
        if self.feature_projector is not None:
            projected_features, log_det = self.feature_projector(features)
        else:
            projected_features = features
            log_det = torch.zeros(features.size(0), device=features.device, requires_grad=False)
        if self.allowed_ends is not None:
            if additional_allowed_ends_per_instance is None:
                additional_allowed_ends_per_instance = [set() for _ in features.size(0)]
            allowed_ends_per_instance = [
                [i for i, ix in enumerate(valid_classes) if ix.item() in (set(self.allowed_ends) | set(additional_allowed_ends))]
                for additional_allowed_ends in additional_allowed_ends_per_instance
            ]
            assert all(allowed_ends_per_instance), allowed_ends_per_instance
        else:
            allowed_ends_per_instance = None
        elp = self.emission_log_probs(projected_features, valid_classes, constraints)
        scores = self.log_hsmm(self.transition_log_probs(valid_classes), elp,
                               self.initial_log_probs(valid_classes), self.length_log_probs(valid_classes),
                               lengths, add_eos=add_eos, all_batched=self.batched_scores,
                               allowed_ends_per_instance=allowed_ends_per_instance)
        if return_elp: return scores, log_det, elp
        else: return scores, log_det
    def log_likelihood(self, features, lengths, valid_classes_per_instance, spans=None, add_eos=True, use_mean_z=False,
                       additional_allowed_ends_per_instance=None, constraints=None):
        from utils.utils import all_equal
        if valid_classes_per_instance is not None:
            assert all_equal(set(vc.detach().cpu().numpy()) for vc in valid_classes_per_instance)
            valid_classes = valid_classes_per_instance[0]; C = len(valid_classes)
        else:
            valid_classes = None; C = self.n_classes
        scores, log_det = self.score_features(features, lengths, valid_classes, add_eos=add_eos, use_mean_z=use_mean_z,
                                     additional_allowed_ends_per_instance=additional_allowed_ends_per_instance,
                                     constraints=constraints)
        K = scores.size(2); assert K <= self.max_k or (self.max_k == 1 and K == 2)
        if add_eos:
            eos_lengths = lengths + 1
            eos_spans = self.add_eos(spans, lengths) if spans is not None else spans
            eos_C = C + 1
        else:
            eos_lengths = lengths; eos_spans = spans; eos_C = C
        dist = SemiMarkovCRF(scores, lengths=eos_lengths)
        if eos_spans is not None:
            eos_spans_mapped = eos_spans.detach().cpu().clone()
            if valid_classes is not None:
                mapping = {cls.item(): index for index, cls in enumerate(valid_classes)}
                assert len(mapping) == len(valid_classes)
                assert -1 not in mapping
                mapping[-1] = -1; mapping[self.n_classes] = C
                if 0 not in mapping: mapping[0] = 0
            parts = SemiMarkovCRF.struct.to_parts(eos_spans_mapped, (eos_C, K), lengths=eos_lengths).type_as(scores)
            if self.args.sm_train_discriminatively:
                log_likelihood = dist.log_prob(parts).mean()
            else:
                d = parts.dim(); batch_dims = range(d - len(dist.event_shape))
                log_likelihood = dist.struct().score(dist.log_potentials, parts.type_as(dist.log_potentials), batch_dims=batch_dims).mean()
        else:
            log_likelihood = dist.partition.mean()
        return log_likelihood, log_det.mean()
    def viterbi(self, features, lengths, valid_classes_per_instance, add_eos=True, use_mean_z=False,
                additional_allowed_ends_per_instance=None, constraints=None, predict_single=False, return_elp=False):
        from utils.utils import all_equal
        if valid_classes_per_instance is not None:
            assert all_equal(set(vc.detach().cpu().numpy()) for vc in valid_classes_per_instance)
            valid_classes = valid_classes_per_instance[0]; C = len(valid_classes)
        else:
            valid_classes = None; C = self.n_classes
        scores, log_det, elp = self.score_features(features, lengths, valid_classes, add_eos=add_eos, use_mean_z=use_mean_z,
                                     additional_allowed_ends_per_instance=additional_allowed_ends_per_instance,
                                     constraints=constraints, return_elp=True)
        if add_eos: eos_lengths = lengths + 1
        else: eos_lengths = lengths
        dist = SemiMarkovCRF(scores, lengths=eos_lengths)
        pred_spans, extra = dist.struct.from_parts(dist.argmax)
        pred_spans_unmap = pred_spans.detach().cpu()
        if valid_classes is not None:
            mapping = {index: cls.item() for index, cls in enumerate(valid_classes)}
            assert len(mapping.values()) == len(mapping)
            assert -1 not in mapping.values()
            mapping[-1] = -1; mapping[C] = self.n_classes
            pred_spans_unmap.apply_(lambda x: mapping[x])
        if return_elp: return pred_spans_unmap, elp
        else: return pred_spans_unmap

class ComponentSemiMarkovModule(SemiMarkovModule):
    @classmethod
    def add_args(cls, parser):
        parser.add_argument('--sm_component_decompose_steps', action='store_true')
        parser.add_argument('--sm_component_mean_layers', type=int, default=2)
        parser.add_argument('--sm_component_length_layers', type=int, default=2)
        parser.add_argument('--sm_component_embedding_dim', type=int, default=100)
        parser.add_argument('--sm_component_z_dim', type=int, default=0)
        parser.add_argument('--sm_component_z_hidden_dim', type=int, default=100)
        parser.add_argument('--no_sm_compound_structure', action='store_false', dest='sm_compound_structure')
    def __init__(self, args, n_classes: int, n_components: int, class_to_components: Dict[int, Set[int]],
                 feature_dim: int, allow_self_transitions=False, per_class_bias=True,
                 allowed_starts: Set[int] = None, allowed_transitions: Dict[int, Set[int]] = None,
                 allowed_ends: Set[int] = None, merge_classes: Dict[int, int] = None):
        self.args = args
        self.n_components = n_components
        self.embedding_dim = self.args.sm_component_embedding_dim
        self.z_dim = self.args.sm_component_z_dim
        self.embedding_and_z_dim = self.embedding_dim + self.z_dim
        if self.args.sm_compound_structure: self.structure_emb_dim = self.embedding_and_z_dim
        else: self.structure_emb_dim = self.embedding_dim
        self.class_to_components = class_to_components
        self.component_to_classes: Dict[int, Set[int]] = {}
        for cls, components in self.class_to_components.items():
            for component in components:
                assert 0 <= component < n_components
                if component not in self.component_to_classes: self.component_to_classes[component] = set()
                self.component_to_classes[component].add(cls)
        self.per_class_bias = per_class_bias
        self.mean_layers = self.args.sm_component_mean_layers
        self.length_layers = self.args.sm_component_length_layers
        self.use_separate_embeddings = True
        super(ComponentSemiMarkovModule, self).__init__(args, n_classes, feature_dim, allow_self_transitions,
                                                        allowed_starts, allowed_transitions, allowed_ends,
                                                        merge_classes=merge_classes)
    def init_params(self):
        def make_embeddings():
            return nn.EmbeddingBag(num_embeddings=self.n_components, embedding_dim=self.embedding_dim, mode="mean", sparse=False)
        if self.use_separate_embeddings:
            self.initial_embeddings = make_embeddings()
            self.transition_embeddings = make_embeddings()
            self.emission_embeddings = make_embeddings()
            self.length_embeddings = make_embeddings()
        else:
            self.shared_embeddings = make_embeddings()
        self.initial_weights = nn.Linear(self.structure_emb_dim, 1, bias=True)
        if self.per_class_bias: self.initial_bias = nn.Parameter(torch.zeros(self.n_classes))
        else: self.initial_bias = None
        self.transition_weights = nn.Linear(self.structure_emb_dim, self.structure_emb_dim, bias=True)
        if self.per_class_bias: self.transition_bias = nn.Parameter(torch.zeros(self.n_classes))
        else: self.transition_bias = None
        emission_mean_mlp = [nn.Linear(self.embedding_and_z_dim, self.embedding_dim)]
        for _ in range(self.mean_layers): emission_mean_mlp.append(ResidualLayer(self.embedding_dim, self.embedding_dim))
        emission_mean_mlp.append(nn.Linear(self.embedding_dim, self.feature_dim))
        self.emission_mean_mlp = nn.Sequential(*emission_mean_mlp)
        self.emission_mean_bias = nn.Parameter(torch.zeros(self.feature_dim))
        length_mlp = [nn.Linear(self.structure_emb_dim, self.embedding_dim)]
        for _ in range(self.length_layers): length_mlp.append(ResidualLayer(self.embedding_dim, self.embedding_dim))
        length_mlp.append(nn.Linear(self.embedding_dim, 1))
        self.length_mlp = nn.Sequential(*length_mlp)
        if self.per_class_bias: self.length_bias = nn.Parameter(torch.zeros(self.n_classes))
        else: self.length_bias = None
        if self.z_dim != 0:
            self.encoder = Encoder(self.args, self.feature_dim, self.args.sm_component_z_hidden_dim)
            self.encoder_to_params = nn.Linear(self.args.sm_component_z_hidden_dim, self.z_dim * 2)
        gaussian_cov = torch.eye(self.feature_dim).float()
        self.gaussian_cov = nn.Parameter(gaussian_cov, requires_grad=False)
        for name, param in self.named_parameters():
            if param.dim() > 1 and name not in ['gaussian_cov']:
                xavier_uniform_(param)
    def flatten_parameters(self):
        if self.z_dim != 0: self.encoder.flatten_parameters()
    def _initialize_gaussian_means(self, mean):
        self.emission_mean_bias.data.zero_(); self.emission_mean_bias.data.add_(mean.squeeze(0))
    def enc(self, features, lengths):
        encoded = self.encoder(features, lengths, output_padding_value=0)
        params = self.encoder_to_params(encoded.max(1)[0])
        mean = params[:, :self.z_dim]; logvar = params[:, self.z_dim:]
        return mean, logvar
    def _get_kl(self, mean, logvar):
        return -0.5 * (logvar - torch.pow(mean, 2) - torch.exp(logvar) + 1)
    def _get_z_and_kl(self, features, lengths, use_mean=False):
        batch_size = features.size(0)
        if self.z_dim > 0:
            mean, logvar = self.enc(features, lengths)
            z = mean.new(batch_size, self.z_dim).normal_(0, 1)
            z = (0.5 * logvar).exp() * z + mean
            kl = self._get_kl(mean, logvar).sum(1)
            if use_mean: z = mean
        else:
            z = torch.zeros(batch_size, 1, device=features.device)
            kl = torch.zeros(batch_size, device=features.device)
        return z, kl
    def set_z(self, features, lengths, use_mean=False):
        self.z, self.kl = self._get_z_and_kl(features, lengths, use_mean)
    def embed_classes(self, component_embeddings, valid_classes, is_structure, merge_classes=False):
        if valid_classes is None:
            valid_classes = torch.arange(self.n_classes, device=component_embeddings.weight.device)
        if merge_classes and self.merge_classes is not None:
            valid_classes = torch.LongTensor([self.merge_classes[ix.item()] for ix in valid_classes]).to(valid_classes.device)
        assert valid_classes.dim() == 1, valid_classes
        offset = 0; offsets = [offset]; indices = []
        for cls in valid_classes.detach().cpu().numpy():
            components = self.class_to_components[cls]
            offset += len(components); offsets.append(offset); indices.extend(components)
        assert offsets[-1] == len(indices); offsets = offsets[:-1]
        emb = component_embeddings(torch.tensor(indices, device=component_embeddings.weight.device, dtype=torch.long),
                                   torch.tensor(offsets, device=component_embeddings.weight.device, dtype=torch.long))
        n_valid_c, e_dim = emb.size(); emb = emb.unsqueeze(0)
        if self.z_dim > 0 and (self.args.sm_compound_structure or not is_structure):
            assert hasattr(self, 'z')
            batch, z_dim = self.z.size(); emb = emb.expand(batch, n_valid_c, e_dim)
            z = self.z.unsqueeze(1).expand(batch, n_valid_c, z_dim)
            emb = torch.cat((emb, z), dim=-1)
        return emb
    @property
    def batched_scores(self):
        return True
    def initial_log_probs(self, valid_classes):
        class_embeddings = self.embed_classes(self.initial_embeddings if self.use_separate_embeddings else self.shared_embeddings,
                                              valid_classes, is_structure=True, merge_classes=False)
        x = self.initial_weights(class_embeddings); x = x.squeeze(-1)
        if self.init_constraints is not None:
            constraints = self.init_constraints
            if valid_classes is not None: constraints = constraints[valid_classes]
            x = x.masked_fill(constraints.unsqueeze(0).expand_as(x), BIG_NEG)
        if self.initial_bias is not None: x += self.initial_bias[valid_classes]
        return torch.log_softmax(x, dim=-1)
    def transition_log_probs(self, valid_classes):
        class_embeddings = self.embed_classes(self.transition_embeddings if self.use_separate_embeddings else self.shared_embeddings,
                                              valid_classes, is_structure=True, merge_classes=False)
        x = self.transition_weights(class_embeddings)
        x = torch.einsum("bfe,bte->btf", [x, class_embeddings])
        if self.transition_constraints is not None:
            constraints = self.transition_constraints
            if valid_classes is not None: constraints = constraints[valid_classes][:,valid_classes]
            x = x.masked_fill(constraints.unsqueeze(0).expand_as(x), BIG_NEG)
        if self.transition_bias is not None:
            x += self.transition_bias[valid_classes].unsqueeze(0).unsqueeze(-1).expand_as(x)
        if not self.allow_self_transitions:
            x = x.masked_fill(torch.eye(len(valid_classes), device=x.device).bool().unsqueeze(0).expand_as(x), BIG_NEG)
        return F.log_softmax(x, dim=1)  # batch,to,from
    def emission_log_probs(self, features, valid_classes, constraints):
        class_embeddings = self.embed_classes(self.emission_embeddings if self.use_separate_embeddings else self.shared_embeddings,
                                              valid_classes, is_structure=False, merge_classes=True)
        class_means = self.emission_mean_mlp(class_embeddings)
        class_means += self.emission_mean_bias.unsqueeze(0).unsqueeze(0).expand_as(class_means)
        elp = self._emission_log_probs_with_means(features, class_means)
        if constraints is not None: elp = elp + constraints
        return elp
    def length_log_probs(self, valid_classes):
        class_embeddings = self.embed_classes(self.length_embeddings if self.use_separate_embeddings else self.shared_embeddings,
                                              valid_classes, is_structure=True, merge_classes=True)
        class_log_rates = self.length_mlp(class_embeddings).squeeze(-1)
        if self.length_bias is not None:
            class_log_rates += self.length_bias[valid_classes].unsqueeze(0).expand_as(class_log_rates)
        return self._length_log_probs_with_rates(class_log_rates)

# ---- models/semimarkov/semimarkov.py (training/inference wrapper + constraints wiring) ----
import copy
import numpy as np
import time
import torch
from utils.utils import all_equal
from models.model import Model, make_optimizer, make_data_loader
from models.semimarkov.semimarkov_modules import SemiMarkovModule, ComponentSemiMarkovModule
from models.semimarkov import semimarkov_utils

class SemiMarkovModel(Model):
    @classmethod
    def add_args(cls, parser):
        SemiMarkovModule.add_args(parser)
        ComponentSemiMarkovModule.add_args(parser)
        parser.add_argument('--sm_component_model', action='store_true')
        parser.add_argument('--sm_constrain_transitions', action='store_true')
        parser.add_argument('--sm_constrain_with_narration', choices=['train', 'test'], nargs='*', default=[])
        parser.add_argument('--sm_constrain_narration_weight', type=float, default=-1e4)
        parser.add_argument('--sm_train_discriminatively', action='store_true')
        parser.add_argument('--sm_hidden_markov', action='store_true')
        parser.add_argument('--sm_predict_single', action='store_true')
    @classmethod
    def from_args(cls, args, train_data):
        n_classes = train_data.corpus.n_classes
        feature_dim = train_data.feature_dim
        allow_self_transitions = True
        assert args.sm_max_span_length is not None
        if args.sm_constrain_transitions:
            (allowed_starts, allowed_transitions, allowed_ends, ordered_indices_by_task) = train_data.get_allowed_starts_and_transitions()
            if allow_self_transitions:
                for src in range(n_classes):
                    if src not in allowed_transitions: allowed_transitions[src] = set()
                    allowed_transitions[src].add(src)
        else:
            allowed_starts, allowed_transitions, allowed_ends, ordered_indices_by_task = None, None, None, None
        if args.annotate_background_with_previous and not args.no_merge_classes:
            merge_classes = {}
            for task, indices in train_data.corpus._indices_by_task.items():
                background_indices = [ix for ix in indices if ix in train_data.corpus._background_indices]
                nonbackground_indices = [ix for ix in indices if ix not in train_data.corpus._background_indices]
                canon_bkg_ix = background_indices[0]
                for ix in background_indices: merge_classes[ix] = canon_bkg_ix
                for ix in nonbackground_indices: merge_classes[ix] = ix
        else:
            merge_classes = None
        if args.sm_component_model:
            if args.sm_component_decompose_steps:
                n_components = train_data.corpus.n_components
                class_to_components = copy.copy(train_data.corpus.label_indices2component_indices)
            else:
                n_components = n_classes
                class_to_components = {cls: {cls} for cls in range(n_classes)}
            model = ComponentSemiMarkovModule(args, n_classes, n_components=n_components, class_to_components=class_to_components,
                                              feature_dim=feature_dim, allow_self_transitions=allow_self_transitions,
                                              allowed_starts=allowed_starts, allowed_transitions=allowed_transitions,
                                              allowed_ends=allowed_ends, merge_classes=merge_classes)
        else:
            model = SemiMarkovModule(args, n_classes, feature_dim, allow_self_transitions=allow_self_transitions,
                                     allowed_starts=allowed_starts, allowed_transitions=allowed_transitions,
                                     allowed_ends=allowed_ends, merge_classes=merge_classes)
        return SemiMarkovModel(args, n_classes, feature_dim, model, ordered_indices_by_task)
    def __init__(self, args, n_classes, feature_dim, model, ordered_indices_by_task=None):
        self.args = args
        self.n_classes = n_classes
        self.feature_dim = feature_dim
        self.model = model
        self.ordered_indices_by_task = ordered_indices_by_task
        if args.cuda: self.model.cuda()
    def fit_supervised(self, train_data):
        assert not self.args.sm_component_model
        assert not self.args.sm_constrain_transitions
        loader = make_data_loader(self.args, train_data, batch_by_task=False, shuffle=False, batch_size=1)
        features, labels = [], []
        for batch in loader:
            features.append(batch['features'].squeeze(0))
            labels.append(batch['gt_single'].squeeze(0))
        self.model.fit_supervised(features, labels)
    def make_additional_allowed_ends(self, tasks, lengths):
        if self.ordered_indices_by_task is not None:
            addl_allowed_ends = []
            for task, length in zip(tasks, lengths):
                ord_indices = self.ordered_indices_by_task[task]
                if length.item() < len(ord_indices): this_allowed_ends = [ord_indices[length.item()-1]]
                else: this_allowed_ends = []
                addl_allowed_ends.append(this_allowed_ends)
        else:
            addl_allowed_ends = None
        return addl_allowed_ends
    def expand_constraints(self, datasplit, task, task_indices, constraints):
        task_indices = list(task_indices.cpu().numpy())
        step_indices = datasplit.get_ordered_indices_no_background()[task]
        assert constraints.size(2) == len(step_indices)
        constraints_expanded = torch.zeros((constraints.size(0), constraints.size(1), len(task_indices)))
        for index, label in enumerate(step_indices):
            constraints_expanded[:,:,task_indices.index(label)] = constraints[:,:,index]
        return constraints_expanded
    def fit(self, train_data, use_labels: bool, callback_fn=None):
        self.model.train(); self.model.flatten_parameters()
        if use_labels: assert not self.args.sm_constrain_transitions
        initialize = True
        if use_labels and self.args.sm_supervised_method in ['closed-form', 'closed-then-gradient']:
            self.fit_supervised(train_data)
            if self.args.sm_supervised_method == 'closed-then-gradient':
                initialize = False; callback_fn(-1, {})
            else:
                return
        if self.args.sm_init_non_projection_parameters_from:
            initialize = False
            if callback_fn: callback_fn(-1, {})
        optimizer, scheduler = make_optimizer(self.args, self.model.parameters())
        big_loader = make_data_loader(self.args, train_data, batch_by_task=False, shuffle=True, batch_size=100)
        samp = next(iter(big_loader)); big_features = samp['features']; big_lengths = samp['lengths']
        if self.args.cuda: big_features = big_features.cuda(); big_lengths = big_lengths.cuda()
        if initialize: self.model.initialize_gaussian(big_features, big_lengths)
        loader = make_data_loader(self.args, train_data, batch_by_task=True, shuffle=True, batch_size=self.args.batch_size)
        C = self.n_classes; K = self.args.sm_max_span_length
        for epoch in range(self.args.epochs):
            start_time = time.time(); self.model.train()
            losses = []; multi_batch_losses = []; nlls = []; kls = []; log_dets = []
            num_frames = 0; num_videos = 0; train_nll = 0; train_kl = 0; train_log_det = 0
            for batch_ix, batch in enumerate(loader):
                tasks = batch['task_name']; videos = batch['video_name']
                features = batch['features']; task_indices = batch['task_indices']; lengths = batch['lengths']
                if 'train' in self.args.sm_constrain_with_narration:
                    from utils.utils import all_equal
                    assert all_equal(tasks)
                    constraints_expanded = self.expand_constraints(train_data, tasks[0], task_indices[0], 1 - batch['constraints'])
                    constraints_expanded *= self.args.sm_constrain_narration_weight
                else:
                    constraints_expanded = None
                num_frames += lengths.sum().item(); num_videos += len(lengths)
                if self.args.cuda:
                    features = features.cuda(); lengths = lengths.cuda()
                    if constraints_expanded is not None: constraints_expanded = constraints_expanded.cuda()
                if use_labels:
                    labels = batch['gt_single'];
                    if self.args.cuda: labels = labels.cuda()
                    spans = semimarkov_utils.labels_to_spans(labels, max_k=K); use_mean_z = True
                else:
                    spans = None; use_mean_z = False
                addl_allowed_ends = self.make_additional_allowed_ends(tasks, lengths)
                ll, log_det = self.model.log_likelihood(features, lengths, valid_classes_per_instance=task_indices,
                                                         spans=spans, add_eos=True, use_mean_z=use_mean_z,
                                                         additional_allowed_ends_per_instance=addl_allowed_ends,
                                                         constraints=constraints_expanded)
                nll = -ll; kl = self.model.kl.mean()
                if use_labels: this_loss = nll - log_det
                else: this_loss = nll - log_det + kl
                multi_batch_losses.append(this_loss); nlls.append(nll.item()); kls.append(kl.item()); log_dets.append(log_det.item())
                train_nll += (nll.item() * len(videos)); train_kl += (kl.item() * len(videos)); train_log_det += (log_det.item() * len(videos))
                losses.append(this_loss.item())
                if len(multi_batch_losses) >= self.args.batch_accumulation:
                    loss = sum(multi_batch_losses) / len(multi_batch_losses); loss.backward(); multi_batch_losses = []
                    if self.args.max_grad_norm is not None:
                        torch.nn.utils.clip_grad_norm_(self.model.parameters(), self.args.max_grad_norm)
                    optimizer.step(); self.model.zero_grad()
            train_loss = np.mean(losses)
            if scheduler is not None: scheduler.step(train_loss)
            callback_fn(epoch, {'train_loss': train_loss,
                                'train_nll_frame_avg': train_nll / max(1, num_frames),
                                'train_kl_vid_avg': train_kl / max(1, num_videos),
                                'train_recon_bound': (train_nll + train_kl) / max(1, num_frames)})
    def predict(self, test_data):
        self.model.eval(); self.model.flatten_parameters()
        predictions = {}
        loader = make_data_loader(self.args, test_data, shuffle=False, batch_by_task=True, batch_size=self.args.batch_size)
        for batch in loader:
            features = batch['features']; task_indices = batch['task_indices']; lengths = batch['lengths']
            videos = batch['video_name']; tasks = batch['task_name']
            assert len(set(tasks)) == 1; task = next(iter(tasks))
            if 'test' in self.args.sm_constrain_with_narration:
                constraints_expanded = self.expand_constraints(test_data, task, task_indices[0], 1 - batch['constraints'])
                constraints_expanded *= self.args.sm_constrain_narration_weight
            else:
                constraints_expanded = None
            if self.args.cuda:
                features = features.cuda(); task_indices = [ti.cuda() for ti in task_indices]
                lengths = lengths.cuda();
                if constraints_expanded is not None: constraints_expanded = constraints_expanded.cuda()
            addl_allowed_ends = self.make_additional_allowed_ends(tasks, lengths)
            pred_spans, elp = self.model.viterbi(features, lengths, task_indices, add_eos=True, use_mean_z=True,
                                                 additional_allowed_ends_per_instance=addl_allowed_ends,
                                                 constraints=constraints_expanded, return_elp=True)
            pred_labels = semimarkov_utils.spans_to_labels(pred_spans)
            pred_labels_trim_s = self.model.trim(pred_labels, lengths, check_eos=True)
            for ix, (video, pred_labels_trim) in enumerate(zip(videos, pred_labels_trim_s)):
                preds = pred_labels_trim.numpy(); predictions[video] = preds
        return predictions

