from collections import defaultdict
class CrosstaskDatasplit:
    # ... class initialization, loading omitted ...
    def get_ordered_indices_no_background(self):
        ordered_indices_by_task = {}
        for task in self._corpus._all_tasks:
            indices = [self._corpus._index(self._corpus.get_label(task.index, step)) for step in task.steps]
            ordered_indices_by_task[task.index] = indices
        return ordered_indices_by_task
    def get_allowed_starts_and_transitions(self):
        allowed_starts = set(); allowed_transitions = {}; allowed_ends = set()
        ordered_indices_by_task = {}
        for task in self._corpus._all_tasks:
            if self.remove_background:
                indices = self.get_ordered_indices_no_background()[task.index]
                ordered_indices_by_task[task.index] = indices
                for src, tgt in zip(indices, indices[1:]):
                    if src not in allowed_transitions: allowed_transitions[src] = set()
                    allowed_transitions[src].add(tgt)
                allowed_starts.add(indices[0]); allowed_ends.add(indices[-1])
            else:
                step_indices = [self._corpus._index(self._corpus.get_label(task.index, step)) for step in task.steps]
                background_indices = [self._corpus._index(lbl) for lbl in self._corpus.BACKGROUND_LABELS_BY_TASK[task.index]]
                indices = []
                for ix in range(len(step_indices)):
                    indices.append(background_indices[ix]); indices.append(step_indices[ix])
                indices.append(background_indices[-1])
                for src, tgt in zip(indices, indices[1:]):
                    if src not in allowed_transitions: allowed_transitions[src] = set()
                    allowed_transitions[src].add(tgt)
                allowed_starts.add(indices[0]); allowed_ends.add(indices[-1]); ordered_indices_by_task[task.index] = indices
        return allowed_starts, allowed_transitions, allowed_ends, ordered_indices_by_task

