// Stage-1: Progressive distillation with pseudo-labels (teacher logits) and word-level KL (SeqKD+KL). MLPs frozen.
// File: trainer/kd_trainer.py (KD loss) + train_mamba2/train_hybrid.py (freeze policy)
class KDTrainer(SFTTrainer):
    def compute_loss(self, model, inputs, return_outputs=False):
        self.teacher_model.eval()
        with torch.no_grad():
            outputs_teacher = self.teacher_model(input_ids=inputs["input_ids"], attention_mask=inputs["attention_mask"], labels=inputs["labels"])
        teacher_logits = outputs_teacher.logits.detach()
        outputs_student = model(input_ids=inputs["input_ids"], attention_mask=inputs["attention_mask"], labels=inputs["labels"]) if self.ce_weight > 0 else model(input_ids=inputs["input_ids"], attention_mask=inputs["attention_mask"])
        student_logits = outputs_student.logits
        cross_entropy_loss = (0.0 if self.ce_weight == 0 else outputs_student.loss)
        kl_loss = F.kl_div(F.log_softmax(student_logits, dim=-1), F.softmax(teacher_logits, dim=-1), reduction='batchmean')
        return self.kl_weight * kl_loss + self.ce_weight * cross_entropy_loss

